33	// LoadData reads and parses a template data file. The format is derived
34	// from the file extension: .json/.jsonc, .yaml/.yml, or .toml.
35	func LoadData(path string) (*Data, error) {
36		raw, err := os.ReadFile(path)
37		if err != nil {
38			return nil, fmt.Errorf("failed to read data file: %w", err)
39		}
40	
41		ext := strings.TrimPrefix(strings.ToLower(filepath.Ext(path)), ".")
42	
43		var root map[string]json.RawMessage
44	
45		switch ext {
46		case JSON, JSONC:
47			raw = []byte(jsonutil.StripComments(string(raw)))
48	
49			if err := json.Unmarshal(raw, &root); err != nil {
50				return nil, fmt.Errorf("failed to parse data file: %w", err)
51			}
52		case YAML, YML:
53			var generic map[string]any
54	
55			if err := yaml.Unmarshal(raw, &generic); err != nil {
56				return nil, fmt.Errorf("failed to parse data file: %w", err)
57			}
58	
59			if root, err = normalize(generic); err != nil {
60				return nil, fmt.Errorf("failed to parse data file: %w", err)
61			}
62		case TOML, TML:
63			var generic map[string]any
64	
65			if err := toml.Unmarshal(raw, &generic); err != nil {
66				return nil, fmt.Errorf("failed to parse data file: %w", err)
67			}
68	
69			if root, err = normalize(generic); err != nil {
70				return nil, fmt.Errorf("failed to parse data file: %w", err)
71			}
72		default:
73			return nil, fmt.Errorf("unsupported data file extension: %s", ext)
74		}
75	
76		data := &Data{}
77	
78		if env, OK := root["env"]; OK {
79			data.Env = env
80		}
81	
82		if segmentsRaw, OK := root["segments"]; OK {
83			var segments map[string]json.RawMessage
84	
85			if err := json.Unmarshal(segmentsRaw, &segments); err != nil {
86				return nil, fmt.Errorf("failed to parse segments in data file: %w", err)
87			}
88	
89			data.Segments = segments
90		}
91	
92		return data, nil
93	}
94	
95	// normalize re-marshals a generically decoded section (as produced by the
96	// YAML/TOML unmarshalers) to a map of raw JSON so the rest of the pipeline
97	// can treat all formats uniformly.
98	func normalize(generic map[string]any) (map[string]json.RawMessage, error) {
99		root := make(map[string]json.RawMessage, len(generic))
100	
101		for key, value := range generic {
102			b, err := json.Marshal(sanitize(value))
103			if err != nil {
104				return nil, err
105			}
106	
107			root[key] = b
108		}
109	
110		return root, nil
111	}
112	
113	// sanitize recursively converts map[any]any (which the YAML/TOML decoders
114	// may produce for nested maps) into map[string]any so encoding/json can
115	// marshal it.
116	func sanitize(value any) any {
117		switch v := value.(type) {
118		case map[any]any:
119			m := make(map[string]any, len(v))
120			for key, val := range v {
121				m[fmt.Sprintf("%v", key)] = sanitize(val)
122			}
123	
124			return m
125		case map[string]any:
126			m := make(map[string]any, len(v))
127			for key, val := range v {
128				m[key] = sanitize(val)
129			}
130	
131			return m
132		case []any:
133			s := make([]any, len(v))
134			for i, val := range v {
135				s[i] = sanitize(val)
136			}
137	
138			return s
139		default:
140			return v
141		}
142	}
143	
144	// EnvFlags parses the env section for the properties that route into
145	// runtime.Flags instead of the template cache. Unknown keys are ignored.
146	func (d *Data) EnvFlags() (*EnvData, error) {
147		env := &EnvData{}
148	
149		if len(d.Env) == 0 {
150			return env, nil
151		}
152	
153		if err := json.Unmarshal(d.Env, env); err != nil {
154			return nil, fmt.Errorf("failed to parse env data: %w", err)
155		}
156	
157		return env, nil
158	}
